const pipeline = $('Pull revenue pipeline').all().map(i => i.json);
const gaps = $('Pull conversion gaps').all().map(i => i.json).filter(r => r.lead_id);
const performance = $('Pull recent wins + losses').all().map(i => i.json);

const today = new Date().toISOString().slice(0, 10);
const stalledLeads = gaps.length;
const interestedCount = pipeline.find(p => p.marketing_status === 'Interested')?.lead_count || 0;
const contactedCount = pipeline.find(p => p.marketing_status === 'Contacted')?.lead_count || 0;

const prompt = `You are Bridge_CRO_BOT running the daily revenue engine. Today is ${today}.

REVENUE PIPELINE:
${JSON.stringify(pipeline, null, 2)}

STALLED CONVERSIONS (no touch in 7+ days):
${JSON.stringify(gaps.slice(0, 5), null, 2)}

RECENT PROJECT OUTCOMES:
${JSON.stringify(performance, null, 2)}

Your job: Generate 3-5 specific, actionable revenue opportunities. For each opportunity:
1. Identify a concrete action (re-engage stalled lead, upsell existing client, new campaign)
2. Estimate revenue potential ($)
3. Identify which agent should execute
4. Provide a specific memo subject and brief action body

Focus on highest-ROI, lowest-effort opportunities first.
Return a JSON array of opportunities:
[{"priority": 1, "type": "re_engage|upsell|new_campaign", "target": "lead_id or general", "revenue_potential_usd": 0, "effort": "low|medium|high", "execute_agent": "bizdev|marketing|pm", "memo_subject": "...", "memo_body": "..."}]`;

return [{ json: { prompt, stalled_count: stalledLeads, interested_count: interestedCount,
  contacted_count: contactedCount, today } }];

const raw = $json.response || '';
const ctx = $('Assemble CRO analysis').first().json;

let opportunities = [];
try {
  const cleaned = raw.trim().replace(/^```(?:json)?/, '').replace(/```$/, '').trim();
  const m = cleaned.match(/\[[\s\S]*\]/);
  if (m) opportunities = JSON.parse(m[0]);
} catch(e) { opportunities = []; }

// Keep top 3 by priority
const top = opportunities.slice(0, 3);
return top.map(o => ({ json: {
  to_agent: o.execute_agent || 'bizdev',
  memo_type: 'revenue_opportunity',
  priority: o.priority === 1 ? 'high' : 'normal',
  subject: o.memo_subject || 'CRO Revenue Opportunity',
  body_json: {
    ...o,
    source: 'cro_revenue_engine',
    generated_date: ctx.today,
    stalled_pipeline: ctx.stalled_count,
    attempt_count: 0
  }
}}));
